// Compute "today" and "horizon" for the prompt and filtering.
const horizonDays = 180;
const now = new Date();
const todayISO = now.toISOString().slice(0, 10);
const horizon = new Date(now.getTime() + horizonDays * 24 * 3600 * 1000).toISOString().slice(0, 10);

// Centralized sector definitions for the agent prompt
const sector_definitions = [
  "Disaster Risk Management: Activities, systems, and governance whose primary purpose is to anticipate, reduce, manage, and recover from hazards by strengthening risk assessment, preparedness, emergency response capacity, and disaster recovery coordination.",
  "Basic Infrastructure: Reconstruction or provision of essential public utilities and everyday service infrastructure that keeps settlements functioning, including lifeline networks (energy, water, wastewater, heating, waste, transport, communications) and critical public facilities such as hospitals and other health infrastructure.",
  "Housing: Repair, reconstruction, or development of permanent residential dwellings and residential buildings, focused on restoring safe, adequate, long-term living conditions for households.",
  "Urban Resilience: Integrated city- or neighborhood-level planning, governance, and multi-sector interventions that increase a city’s ability to withstand and adapt to shocks and long-term stresses while improving recovery capacity and overall urban livability."
].join("\n");

return [{
  json: {
    todayISO,
    horizon,
    horizonDays,
    sector_definitions
  }
}];

function stripFences(s) {
  return String(s || "")
    .trim()
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();
}

function parsePossiblyDoubleEncoded(raw) {
  if (raw == null) return null;
  if (typeof raw === "object") return raw;

  const cleaned = stripFences(String(raw));
  let p;
  try { p = JSON.parse(cleaned); } catch { return null; }

  if (typeof p === "string") {
    try { p = JSON.parse(p); } catch { return null; }
  }
  return p;
}

const raw = $json.output ?? $json.text ?? $json.response ?? "";
const parsed = parsePossiblyDoubleEncoded(raw);

if (!parsed || !Array.isArray(parsed.events)) {
  throw new Error("No valid events[] found.");
}

return [{ json: { events: parsed.events } }];

const crypto = require('crypto');

function stripDiacritics(s) {
  return s.normalize('NFKD').replace(/[\u0300-\u036f]/g, '');
}

function normTitle(input) {
  let s = String(input || '').trim();
  s = stripDiacritics(s);
  s = s.toLowerCase();

  // replace punctuation with spaces (keeps alphanumerics)
  s = s.replace(/[^a-z0-9]+/g, ' ');

  // collapse whitespace
  s = s.replace(/\s+/g, ' ').trim();

  return s;
}

function sha256Hex(s) {
  return crypto.createHash('sha256').update(s, 'utf8').digest('hex');
}

function normUrl(input) {
  const raw = String(input || '').trim();
  if (!raw) return '';
  try {
    const u = new URL(raw);
    u.hash = '';
    const drop = ['utm_source','utm_medium','utm_campaign','utm_term','utm_content','fbclid','gclid'];
    drop.forEach(k => u.searchParams.delete(k));
    return u.toString().replace(/\/$/, '');
  } catch {
    return raw.replace(/\/$/, '');
  }
}

function normDateToUtcIso(input) {
  if (!input) return '';
  const d = new Date(String(input));
  if (Number.isNaN(d.getTime())) return '';
  return d.toISOString();
}

return $input.all().map(item => {
  const j = item.json || {};

  const titleNorm = normTitle(j.title ?? j.title_en ?? '');
  const titleHash = titleNorm ? sha256Hex(titleNorm) : '';

  // Normalize URL + dates EARLY so DB lookups use the same canonical form as inserts
  const eventUrlNorm = normUrl(j.event_url);
  const eventDateUtc = normDateToUtcIso(j.event_date);
  const eventEndUtc = j.event_end_date ? normDateToUtcIso(j.event_end_date) : j.event_end_date;

  return {
    json: {
      ...j,
      title: j.title ?? j.title_en ?? j.title_uk ?? j.title_de, // keep original if present
      n8n_title_norm: titleNorm,
      n8n_title_hash: titleHash,
      event_url: eventUrlNorm,
      event_date: eventDateUtc,
      event_end_date: eventEndUtc,
    }
  };
});

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

const allowed = new Set(["housing", "infrastructure", "disaster-risk", "urban-resilience"]);

function norm(s) {
  return String(s || "")
    .trim()
    .toLowerCase()
    .replace(/[_\s]+/g, "-");
}

function mapSector(input) {
  const s = norm(input);

  // already valid
  if (allowed.has(s)) return s;

  // common synonyms / variants
  const synonyms = new Map([
    ["basic-infrastructure", "infrastructure"],
    ["critical-infrastructure", "infrastructure"],
    ["health-infrastructure", "infrastructure"],
    ["drm", "disaster-risk"],
    ["disaster-risk-management", "disaster-risk"],
    ["disaster-risk-reduction", "disaster-risk"],
    ["urban-resilience", "urban-resilience"],
    ["resilience", "urban-resilience"],
  ]);

  return synonyms.get(s) || "";
}

const out = [];

for (const item of $input.all()) {
  const j = item.json || {};
  const mapped = mapSector(j.primary_sector);

  // drop items that don't comply (better than inserting wrong data)
  if (!mapped) continue;

  out.push({
    json: {
      ...j,
      primary_sector: mapped,
    }
  });
}

return out;

return $input.all().map(i => ({
  json: {
    ...i.json,
    // join key must exist before the Supabase lookup
    dedupe_key: i.json.n8n_title_hash,
  }
}));

// Collect titles from all incoming items and output ONE item with all unique titles.

function addIfValid(set, v) {
  const s = String(v ?? "").trim();
  if (s) set.add(s);
}

const titles = new Set();

for (const item of $input.all()) {
  const e = item.json || {};
  addIfValid(titles, e.title_uk);
  addIfValid(titles, e.title_en);
  addIfValid(titles, e.title_de);
}

return [{
  json: {
    all_event_titles: Array.from(titles),
    all_event_titles_joined: Array.from(titles).join(" | "),
    count: titles.size
  }
}];

